/** Exact lookup — returns null if signal has no stored embedding */
export function getSignalEmbedding(signalId: string): SignalEmbedding | null {
  return SIGNAL_EMBEDDINGS[signalId] ?? null;
}

/**
 * Cosine similarity between two equal-length vectors.
 * Returns -1 to 1. Requires same space_id on both sides for valid comparison.
 */
export function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length !== b.length) throw new Error(`Dimension mismatch: ${a.length} vs ${b.length}`);
  let dot = 0, normA = 0, normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot   += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  const denom = Math.sqrt(normA) * Math.sqrt(normB);
  return denom === 0 ? 0 : dot / denom;
}

/**
 * Top-N most similar signals by cosine similarity.
 * Powers /signals/:id/similar and Phase 2b projector GTS validation.
 */
export function findSimilarSignals(
  targetId: string,
  topN = 5
): Array<{ signal_id: string; similarity: number }> {
  const target = SIGNAL_EMBEDDINGS[targetId];
  if (!target) return [];
  return Object.entries(SIGNAL_EMBEDDINGS)
    .filter(([id]) => id !== targetId)
    .map(([id, emb]) => ({
      signal_id: id,
      similarity: cosineSimilarity(target.vector, emb.vector),
    }))
    .sort((a, b) => b.similarity - a.similarity)
    .slice(0, topN);
}
